import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

// Define gradientes por tipo de ícono para que todos iguales tengan el mismo color
const gradientsByIcon = {
  FaBriefcase: {
    iconBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    contentBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    arrowBorderColor: "#764ba2",
  },
  FaUniversity: {
    iconBgGradient: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)",
    contentBgGradient: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)",
    arrowBorderColor: "#3b82f6",
  },
  FaCloud: {
    iconBgGradient: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)",
    contentBgGradient: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)",
    arrowBorderColor: "#00a1f1",
  },
};

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022 - Present",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021 - 2022",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014 - 2021",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013 - 2014",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008 - 2013",
    icon: <FaBriefcase />,
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001 - 2008",
    icon: <FaBriefcase />,
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001 - 2006",
    icon: <FaUniversity />,
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2023 - 2024",
    icon: <FaUniversity />,
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022 - 2024",
    icon: <FaUniversity />,
  },
];

// Función para extraer el año final (o el único año si es uno solo)
function getEndYear(dateStr) {
  if (!dateStr) return 0;
  const parts = dateStr.split("-");
  const lastPart = parts[parts.length - 1].trim().toLowerCase();
  if (lastPart === "present") {
    return new Date().getFullYear(); // Año actual si dice "Present"
  }
  // Trata de convertir a número el último año
  const year = parseInt(lastPart, 10);
  return isNaN(year) ? 0 : year;
}

export default function ExperienceTimeline() {
  // Ordenar del más reciente al más antiguo por año final
  const sortedData = [...experienceData].sort(
    (a, b) => getEndYear(b.date) - getEndYear(a.date)
  );

  return (
    <VerticalTimeline>
      {sortedData.map((exp, idx) => {
        // Obtener nombre del ícono para asignar gradientes
        const iconName = exp.icon.type.displayName || exp.icon.type.name;

        // Gradientes por tipo de ícono, default si no existe
        const gradients = gradientsByIcon[iconName] || {
          iconBgGradient: "linear-gradient(135deg, #333 0%, #555 100%)",
          contentBgGradient: "linear-gradient(135deg, #333 0%, #555 100%)",
          arrowBorderColor: "#555",
        };

        return (
          <VerticalTimelineElement
            key={idx}
            date={<span style={{ fontWeight: "bold", color: "white" }}>{exp.date}</span>}
            iconStyle={{
              background: gradients.iconBgGradient,
              color: "#fff",
              boxShadow: "0 0 10px rgba(0,0,0,0.2)",
            }}
            contentStyle={{
              background: gradients.contentBgGradient,
              color: "#fff",
              boxShadow: "0 4px 15px rgba(0,0,0,0.15)",
            }}
            contentArrowStyle={{
              borderRight: `7px solid ${gradients.arrowBorderColor}`,
            }}
            style={{ marginBottom: "10px", marginTop: "10px" }}
            icon={exp.icon}
          >
            <h3>{exp.title}</h3>
            <h4>{exp.company}</h4>
          </VerticalTimelineElement>
        );
      })}
    </VerticalTimeline>
  );
}
